  'legal.terms.definitions.businessCustomer': { fi: 'Yritysasiakas', en: 'Business Customer' },
  'legal.terms.definitions.businessCustomerDesc': { fi: 'Oikeushenkilö, yritys, elinkeinonharjoittaja tai luonnollinen henkilö, joka toimii kaupallisessa tai ammatillisessa ominaisuudessa', en: 'A legal entity, business, trader, or natural person acting in a commercial or professional capacity' },
  'legal.terms.definitions.customer': { fi: 'Asiakas', en: 'Customer' },
